mapper.select:
SELECT
    (
        SELECT COUNT(1)
        FROM ecg_collection_record c
        WHERE c.is_deleted = 0

            AND c.collection_start_time >= #{startTime}


            AND c.collection_start_time < #{endTime}

    ) AS ecgTotalCount,
    (
        SELECT COUNT(1)
        FROM ecg_collection_record c
        WHERE c.is_deleted = 0
          AND c.collection_start_time >= CURDATE()
          AND c.collection_start_time < DATE_ADD(CURDATE(), INTERVAL 1 DAY)
    ) AS todayAddCount,
    (
        SELECT COUNT(1)
        FROM ecg_collection_record c
        WHERE c.is_deleted = 0
          AND c.ai_analysis_status IN (0, 1)

            AND c.collection_start_time >= #{startTime}


            AND c.collection_start_time < #{endTime}

    ) AS pendingAnalyseCount,
    (
        SELECT COUNT(1)
        FROM ecg_collection_record c
        WHERE c.is_deleted = 0
          AND c.report_status = 1

            AND c.collection_start_time >= #{startTime}


            AND c.collection_start_time < #{endTime}

    ) AS pendingAuditCount,
    (
        SELECT COUNT(1)
        FROM ecg_abnormal_warning w
        WHERE w.is_deleted = 0

            AND w.warning_time >= #{startTime}


            AND w.warning_time < #{endTime}

    ) AS alertTotalCount,
    (
        SELECT COUNT(1)
        FROM ecg_abnormal_warning w
        WHERE w.is_deleted = 0
          AND w.handle_status = 3

            AND w.warning_time >= #{startTime}


            AND w.warning_time < #{endTime}

    ) AS alertHandledCount

SELECT w.warning_id AS alertId, w.warning_time AS alertTime, CONCAT( COALESCE(w.patient_name, ''), ' / ', COALESCE(w.gender, CASE p.gender WHEN 1 THEN '男' WHEN 2 THEN '女' ELSE '未知' END), ' / ', COALESCE(w.age, p.age, 0), '岁' ) AS patientInfo, COALESCE(w.dept_name, '未知病区') AS ward, COALESCE(w.warning_type, '-') AS alertType, CASE w.warning_level WHEN 3 THEN '高危' WHEN 2 THEN '中危' WHEN 1 THEN '低危' ELSE '未知' END AS alertLevel, CASE w.handle_status WHEN 0 THEN '待确认' WHEN 1 THEN '待处理' WHEN 2 THEN '处理中' WHEN 3 THEN '已处理' WHEN 4 THEN '已忽略' ELSE '未知' END AS alertStatus, CASE WHEN c.collection_type IN (2, 3) THEN '动态心电图' ELSE '静态心电图' END AS sourceType, COALESCE(NULLIF(p.primary_diagnosis, ''), NULLIF(w.warning_desc, ''), '暂无临床表现记录') AS clinicalSymptom, CASE w.warning_level WHEN 3 THEN '肌钙蛋白偏高；CK-MB偏高；建议急查电解质' WHEN 2 THEN '心肌酶谱轻度异常；建议复查肌钙蛋白' WHEN 1 THEN '建议结合常规检验复核' ELSE '暂无LIS异常提示' END AS lisCheckData FROM ecg_abnormal_warning w LEFT JOIN patient_info p ON w.patient_id = p.patient_id AND p.is_deleted = 0 LEFT JOIN ecg_collection_record c ON w.record_id = c.record_id AND c.is_deleted = 0 WHERE w.is_deleted = 0 AND w.handle_status IN (0, 1, 2)
AND w.warning_time >= #{startTime}
AND w.warning_time < #{endTime}
ORDER BY w.warning_time DESC, w.warning_id DESC

SELECT c.record_id AS ecgId, c.collection_start_time AS collectTime, CONCAT( COALESCE(c.patient_name, ''), ' / ', COALESCE(c.gender, '未知'), ' / ', COALESCE(c.age, 0), '岁' ) AS patientInfo, COALESCE(c.dept_name, '未知病区') AS ward, COALESCE(c.device_name, c.device_id) AS deviceNo, CASE c.display_status WHEN 0 THEN '待分析' WHEN 1 THEN '已分析' WHEN 2 THEN '已审核' WHEN 3 THEN '已驳回' WHEN 4 THEN '采集失败' ELSE '未知' END AS status, COALESCE(NULLIF(c.ai_conclusion_short, ''), NULLIF(a.ai_conclusion, ''), '-') AS aiConclusion FROM ecg_collection_record c LEFT JOIN ecg_ai_diagnosis a ON a.record_id = c.record_id AND a.is_deleted = 0 WHERE c.is_deleted = 0
AND c.collection_start_time >= #{startTime}
AND c.collection_start_time < #{endTime}
ORDER BY c.collection_start_time DESC, c.record_id DESC
